@pytest_asyncio.fixture
async def clear_metrics_tables(state: State):
    """Clears the task metrics tables before each test."""
    await state.task_metrics_store.ch_client.command(TruncateTaskMetricsQuery())
    await state.task_metrics_store.ch_client.command(TruncateTaskMetricsByEntityMinuteQuery())
